interface.definition:
#"SYSTEM_SYSRULES_headerContentLayout"(
  header: #"SYSTEM_SYSRULES_cardLayout"(
    contents: {
      #"SYSTEM_SYSRULES_headingField"(
        text: if(
          ri!isUpdate,
          "Update Inmate",
          "Create Inmate"
        ),
        size: "LARGE",
        fontWeight: "SEMI_BOLD"
      ),
      #"SYSTEM_SYSRULES_richTextDisplayField"(
        labelPosition: "COLLAPSED",
        value: {
          if(
            ri!isUpdate,
            "Update details for the inmate",
            "Enter details for the inmate"
          )
        }
      )
    },
    padding: "STANDARD",
    showBorder: false,
    style: "ACCENT"
  ),
  contents: {
    #"SYSTEM_SYSRULES_columnsLayout"(
      columns: {
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          width: "WIDE",
          contents: {
            #"SYSTEM_SYSRULES_sectionLayout_v1"(
              contents: {
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_textField"(
                            label: "First Name",
                            labelPosition: "ABOVE",
                            required: true,
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/7daa88ab-46be-4aa0-8fd9-53cf52511478"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/7daa88ab-46be-4aa0-8fd9-53cf52511478"],
                            characterLimit: 255,
                            showCharacterCount: false
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_textField"(
                            label: "Last Name",
                            labelPosition: "ABOVE",
                            required: true,
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/897606a4-d50b-4a42-bcd0-e4d68bbb2856"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/897606a4-d50b-4a42-bcd0-e4d68bbb2856"],
                            characterLimit: 255,
                            showCharacterCount: false
                          )
                        )
                      }
                    ),
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_dateField"(
                            label: "Birthdate",
                            labelPosition: "ABOVE",
                            required: true,
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/75dc33ad-bf4a-4c4a-bf81-55c49269ea66"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/75dc33ad-bf4a-4c4a-bf81-55c49269ea66"],
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_fileUploadField_v1"(
                            label: "Picture",
                            target: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1452646",
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/7e4bd5e8-fc29-462e-be26-b3c83494d1ba"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/7e4bd5e8-fc29-462e-be26-b3c83494d1ba"],
                            maxSelections: 1,
                          )
                        ),

                      }
                    ),
                    #"SYSTEM_SYSRULES_textField"(
                      label: "Sentence",
                      labelPosition: "ABOVE",
                      required: true,
                      value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/57926ae8-7f08-4777-bd8e-a3fdc76db037"],
                      saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/57926ae8-7f08-4777-bd8e-a3fdc76db037"],
                      characterLimit: 255,
                      showCharacterCount: false
                    ),
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      alignVertical: "BOTTOM",
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_dateField"(
                            label: "Planned Exit",
                            labelPosition: "ABOVE",
                            required: true,
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/024bdff6-b507-42cb-8f73-505de5ce5f41"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/024bdff6-b507-42cb-8f73-505de5ce5f41"],
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_checkboxField_v1"(
                            labelPosition: "COLLAPSED",
                            spacing: "MORE",
                            choiceLabels: { "Livelong" },
                            choiceValues: { true },
                            value: if(
                              ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/3855ee10-e9c5-4d3f-86ce-3d140949d2e1"],
                              true,
                              null
                            ),
                            saveInto: a!save(
                              ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/3855ee10-e9c5-4d3f-86ce-3d140949d2e1"],
                              if(isnull(save!value), false, true)
                            ),
                            marginAbove: "STANDARD"
                          ),
                        )
                      }
                    ),
                    #"SYSTEM_SYSRULES_sideBySideLayout"(
                      alignVertical: "BOTTOM",
                      items: {
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_dropdownField_v1"(
                            label: "Station",
                            required: true,
                            data: #"urn:appian:record-type:v1:16cdeca3-e0b7-4859-86a9-795adf54d8a2",
                            choiceLabels: #"urn:appian:record-field:v1:16cdeca3-e0b7-4859-86a9-795adf54d8a2/5cd0e531-bede-4d76-8761-65c73515a8d5",
                            choiceValues: #"urn:appian:record-field:v1:16cdeca3-e0b7-4859-86a9-795adf54d8a2/e1197e97-a240-4c9c-8a77-b3f337ac8b86",
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/11e0d5eb-108f-41b7-b76f-28c777c52f45"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/11e0d5eb-108f-41b7-b76f-28c777c52f45"],
                            placeholder: "Select a Station"
                          )
                        ),
                        #"SYSTEM_SYSRULES_sideBySideItem"(
                          item: #"SYSTEM_SYSRULES_textField"(
                            label: "Cell",
                            labelPosition: "ABOVE",
                            required: true,
                            value: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/f978081b-dcdd-443e-a6d2-c9b7d8755b6a"],
                            saveInto: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/f978081b-dcdd-443e-a6d2-c9b7d8755b6a"],
                            characterLimit: 255,
                            showCharacterCount: false
                          )
                        )
                      }
                    )
                  },
                  shape: "SEMI_ROUNDED",
                  padding: "MORE",
                  style: "NONE",
                  showBorder: false,
                  showShadow: true
                )
              },
              marginBelow: "MORE"
            ),
            #"SYSTEM_SYSRULES_ButtonLayout"(
              primaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: if(
                    ri!isUpdate,
                    "Save",
                    "Create"
                  ),
                  submit: true,
                  validate: true,
                  saveInto: {
                    if(
                      ri!isUpdate,
                      {
                        a!save(
                          target: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/6551975d-975e-4e38-b207-d5a6768df82e"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/4811245a-f930-49c9-8070-6f1469f8287c"],
                          value: now()
                        )
                      },
                      {
                        a!save(
                          target: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/94ce3e6f-6412-4843-bcc3-6339e1b55e97"],
                          value: loggedInUser()
                        ),
                        a!save(
                          target: ri!record[#"urn:appian:record-field:v1:b9f2b8a1-aa3c-420e-9856-a362e5c58683/e1b5afa3-902a-422b-a2be-a0e8669be2d8"],
                          value: now()
                        )
                      }
                    )
                  },
                  style: "SOLID"
                )
              },
              secondaryButtons: {
                #"SYSTEM_SYSRULES_buttonWidget_v1"(
                  label: "Cancel",
                  submit: true,
                  validate: false,
                  saveInto: ri!cancel,
                  style: "OUTLINE",
                  value: true
                )
              }
            )
          }
        ),
        #"SYSTEM_SYSRULES_columnLayout"(
          showWhen: #"SYSTEM_SYSRULES_isPageWidth"(
            {
              "DESKTOP_WIDE",
              "DESKTOP",
              "DESKTOP_NARROW",
              "TABLET_LANDSCAPE"
            }
          )
        )
      }
    )
  },
  backgroundColor: "TRANSPARENT",
  isHeaderFixed: true
)
